from pathlib import Path
import struct, re
raw = Path('/app/mystery').read_bytes()
text = Path('/tmp/main_dis.txt').read_text()
addrs = {}
for line in text.splitlines():
    if '#' not in line:
        continue
    comment = line.split('#', 1)[1]
    for m in re.finditer(r'\b([0-9a-fA-F]{6,8})\s+<([^>]+)>', comment):
        a = int(m.group(1), 16); n = m.group(2)
        if 0x400000 <= a < 0x4c0000 and a + 16 <= len(raw):
            addrs[a] = n
print(f'Found {len(addrs)} unique constants')
for a in sorted(addrs):
    b = raw[a:a+16]
    print(f'{a:#010x} {addrs[a]:36s} {b.hex()} {struct.unpack("<4f", b)}')
PY
sed -n '1,80p' /tmp/consts.txt
